document.addEventListener("DOMContentLoaded",()=>{let e=document.body;"default"===localStorage.getItem("theme")?e.classList.add("default-mode"):e.classList.remove("default-mode"),document.addEventListener("click",t=>{if(t.target.closest(".toggle-wrapper")){e.classList.toggle("default-mode");let d=e.classList.contains("default-mode")?"default":"dark";localStorage.setItem("theme",d)}}),fetch("../partials/toggle.html").then(e=>e.text()).then(e=>{document.querySelector(".mode-toggle").innerHTML=e})});